SELECT wr.RESULT_ID AS resultId, wr.PLANT_CD AS plantCd, wr.RESULT_NO AS resultNo, wr.WO_ID AS woId, wr.RESULT_DT AS resultDt, wr.SHIFT AS shift, wr.WORKER_ID AS workerId, wr.WORKCENTER_CD AS workcenterCd, wr.EQUIPMENT_CD AS equipmentCd, wr.ITEM_CD AS itemCd, wr.PROD_QTY AS prodQty, wr.GOOD_QTY AS goodQty, wr.DEFECT_QTY AS defectQty, wr.START_DTM AS startDtm, wr.END_DTM AS endDtm, wr.WORK_TIME AS workTime, wr.SETUP_TIME AS setupTime, wr.DOWN_TIME AS downTime, wr.LOT_NO AS lotNo, wr.RESULT_STATUS AS resultStatus, wr.RESULT_RMK AS resultRmk, wr.REG_USER_ID AS regUserId, wr.REG_DTM AS regDtm FROM PRD_WORK_RESULT wr WHERE 1 = 1
AND wr.PLANT_CD = #{plantCd}
AND wr.ITEM_CD = #{itemCd}
AND wr.RESULT_DT >= #{resultFromDt}
AND wr.RESULT_DT <= #{resultToDt}
ORDER BY wr.RESULT_DT DESC, wr.RESULT_ID DESC

SELECT wr.RESULT_ID AS resultId, wr.PLANT_CD AS plantCd, wr.RESULT_NO AS resultNo, wr.WO_ID AS woId, wr.RESULT_DT AS resultDt, wr.SHIFT AS shift, wr.WORKER_ID AS workerId, wr.WORKCENTER_CD AS workcenterCd, wr.EQUIPMENT_CD AS equipmentCd, wr.ITEM_CD AS itemCd, wr.PROD_QTY AS prodQty, wr.GOOD_QTY AS goodQty, wr.DEFECT_QTY AS defectQty, wr.START_DTM AS startDtm, wr.END_DTM AS endDtm, wr.WORK_TIME AS workTime, wr.SETUP_TIME AS setupTime, wr.DOWN_TIME AS downTime, wr.LOT_NO AS lotNo, wr.RESULT_STATUS AS resultStatus, wr.RESULT_RMK AS resultRmk, wr.REG_USER_ID AS regUserId, wr.REG_DTM AS regDtm FROM PRD_WORK_RESULT wr WHERE 1 = 1
AND wr.PLANT_CD = #{plantCd}
AND wr.ITEM_CD = #{itemCd}
AND wr.RESULT_DT >= #{resultFromDt}
AND wr.RESULT_DT <= #{resultToDt}
ORDER BY wr.RESULT_DT DESC, wr.RESULT_ID DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM PRD_WORK_RESULT wr
WHERE 1 = 1

    AND wr.PLANT_CD = #{plantCd}


    AND wr.ITEM_CD = #{itemCd}


    AND wr.RESULT_DT >= #{resultFromDt}


    AND wr.RESULT_DT <= #{resultToDt}

SELECT COUNT(*)
FROM PRD_WORK_RESULT
WHERE RESULT_DT = #{resultDt}
